/**
 * The corner ribbon(s) — a diagonal highlight sash fixed in the top-left
 * corner, driven by runtime config (scripts/config/banners.js). It fades out as
 * the page scrolls past the hero. Returns null when none are configured.
 * One job: the corner ribbon.
 */

import { h } from '../dom/h.js';
import { banners } from '../config.js';

export function createBanners(): HTMLElement | null {
  if (banners.length === 0) return null;

  // Position comes from the slot (ribbon-0 nearest the corner); colour defaults by
  // slot but can be overridden per banner via `color`.
  const palette = ['orange', 'blue', 'red'];
  const ribbons = banners.map((b, i) => {
    const label = h('span', { class: 'ribbon-text' }, b.text);
    const color = b.color ?? palette[i] ?? 'orange';
    const cls = `corner-ribbon ribbon-${i} ribbon-c-${color}`;
    return b.href
      ? h('a', { class: cls, href: b.href, attrs: { 'aria-label': b.text } }, label)
      : h('div', { class: cls }, label);
  });

  const root = h(
    'div',
    { class: 'corner-banners', attrs: { 'aria-label': 'Highlights' } },
    ...ribbons,
  );

  // Fully visible through the first part of the hero, then fade out — gone (and
  // non-interactive) by the time the hero leaves the view.
  const heroHeight = (): number => {
    const hero = document.querySelector<HTMLElement>('.hero');
    return (hero && hero.offsetHeight) || window.innerHeight;
  };
  let scheduled = 0;
  const apply = () => {
    scheduled = 0;
    const hh = heroHeight();
    const start = hh * 0.45; // begin fading partway down the hero
    const end = hh * 0.9; // fully gone near the end of the hero
    const y = window.scrollY;
    const opacity = y <= start ? 1 : y >= end ? 0 : 1 - (y - start) / (end - start);
    root.style.opacity = opacity.toFixed(3);
    root.style.visibility = opacity <= 0.01 ? 'hidden' : 'visible';
  };
  const onScroll = () => {
    if (!scheduled) scheduled = requestAnimationFrame(apply);
  };
  window.addEventListener('scroll', onScroll, { passive: true });
  window.addEventListener('resize', onScroll, { passive: true });
  apply();

  return root;
}
