/**
 * Money rules for giving. Pure, environment-agnostic — imported by both the
 * browser UI and the Express server so the two can never disagree on what a
 * valid gift amount is. One job: turn human input into trustworthy cents and back.
 */

/** Smallest gift we accept: $1.00. */
export const MIN_AMOUNT_CENTS = 100;
/** Sanity ceiling so a fat-fingered entry can't create a $1,000,000 charge. */
export const MAX_AMOUNT_CENTS = 1_000_000; // $10,000.00

/**
 * Parse free-form dollar input ("25", "$1,000.50", " 40 ") into integer cents.
 * Returns null for anything that isn't a clean, non-negative money value.
 */
export function parseDollarsToCents(input: string): number | null {
  const cleaned = input.replace(/[$,\s]/g, '');
  if (cleaned === '') return null;
  if (!/^\d+(\.\d{1,2})?$/.test(cleaned)) return null;
  const dollars = Number(cleaned);
  if (!Number.isFinite(dollars)) return null;
  return Math.round(dollars * 100);
}

/** True when cents is a whole number inside the accepted range. */
export function isValidAmount(cents: number): boolean {
  return Number.isInteger(cents) && cents >= MIN_AMOUNT_CENTS && cents <= MAX_AMOUNT_CENTS;
}

/** Currency string for display, e.g. 2500 -> "$25", 2550 -> "$25.50". */
export function formatCents(cents: number): string {
  const hasFraction = cents % 100 !== 0;
  return (cents / 100).toLocaleString('en-US', {
    style: 'currency',
    currency: 'USD',
    minimumFractionDigits: hasFraction ? 2 : 0,
    maximumFractionDigits: 2,
  });
}

/** Bare number for the big amount field: 2500 -> "25", 2550 -> "25.50". */
export function centsToInputString(cents: number): string {
  if (cents % 100 === 0) return String(cents / 100);
  return (cents / 100).toFixed(2);
}
