/**
 * "Photo Gallery" — a slideshow of real photos of the ACFI church family.
 * One job: show the congregation as a slideshow.
 */

import { h } from '../dom/h.js';
import { createSlideshow } from '../dom/slideshow.js';
import { content } from '../content/site.js';

export function createGallery(): HTMLElement {
  const { gallery } = content;

  return h(
    'section',
    { class: 'section gallery', id: 'gallery' },
    h(
      'div',
      { class: 'container' },
      h('p', { class: 'eyebrow', attrs: { 'data-reveal': '' } }, gallery.eyebrow),
      h('h2', { class: 'section-title', attrs: { 'data-reveal': '' } }, gallery.title),
      h(
        'div',
        { class: 'gallery-stage', attrs: { 'data-reveal': '' } },
        createSlideshow(gallery.slides.map((s) => ({ src: s.src, alt: s.alt }))),
      ),
    ),
  );
}
