/**
 * The ministries as a clickable card grid. Each card shows a short summary;
 * clicking it opens a dialog box with the ministry's full, verbatim details.
 * One job: show the ministries and open their detail dialogs.
 */

import { h } from '../dom/h.js';
import { openModal } from '../dom/modal.js';
import { content } from '../content/site.js';
import type { MinistryContent } from '../content/site.js';

export function createMinistries(): HTMLElement {
  const { ministries } = content;

  const grid = h(
    'div',
    { class: 'ministry-grid' },
    ...ministries.items.map((m, i) => card(m, i)),
  );

  return h(
    'section',
    { class: 'section ministries', id: 'ministries' },
    h(
      'div',
      { class: 'container' },
      h('p', { class: 'eyebrow', attrs: { 'data-reveal': '' } }, ministries.eyebrow),
      h('h2', { class: 'section-title', attrs: { 'data-reveal': '' } }, ministries.title),
      h('p', { class: 'section-lede', attrs: { 'data-reveal': '' } }, ministries.note),
      grid,
    ),
  );
}

function card(m: MinistryContent, index: number): HTMLElement {
  const el = h(
    'button',
    {
      type: 'button',
      class: 'ministry-card',
      attrs: { 'data-reveal': '', style: `--i:${index}`, 'aria-label': `Read more about ${m.name}` },
    },
    h('span', { class: 'ministry-index' }, String(index + 1).padStart(2, '0')),
    h('h3', { class: 'ministry-name' }, m.name),
    h('p', { class: 'ministry-verse' }, m.verse),
    h('p', { class: 'ministry-body' }, m.summary),
    h('span', { class: 'ministry-more' }, 'View ministry →'),
  );
  el.addEventListener('click', () => openModal(m.name, buildDetail(m)));
  return el;
}

function buildDetail(m: MinistryContent): HTMLElement {
  const sections = m.detail.map((s) =>
    h(
      'div',
      { class: 'modal-section' },
      s.heading ? h('h3', { class: 'modal-section-heading' }, s.heading) : null,
      ...(s.body ?? []).map((p) => h('p', { class: 'modal-paragraph' }, p)),
      s.list
        ? h('ul', { class: 'modal-list' }, ...s.list.map((li) => h('li', {}, li)))
        : null,
    ),
  );

  const header = h(
    'header',
    { class: 'modal-header' },
    h('p', { class: 'modal-eyebrow' }, 'Ministry'),
    h('h2', { class: 'modal-title' }, m.name),
    h('p', { class: 'modal-verse' }, m.verse),
  );

  const main = h(
    'div',
    { class: 'modal-content' },
    ...sections,
    m.leaders ? h('p', { class: 'modal-meta' }, m.leaders) : null,
    m.contact ? h('a', { class: 'modal-contact', href: `mailto:${m.contact}` }, m.contact) : null,
  );

  return h('div', { class: 'modal-body' }, header, main);
}
