/**
 * After Stripe Checkout, the giver returns to "/?gift=success" or
 * "/?gift=cancelled". This reads that flag, shows a friendly banner, and tidies
 * the URL so a refresh doesn't repeat it. One job: acknowledge the return.
 */

import { h } from '../dom/h.js';

type GiftOutcome = 'success' | 'cancelled';

const MESSAGES: Record<GiftOutcome, { title: string; body: string; tone: string }> = {
  success: {
    title: 'Thank you for your generosity 🤍',
    body: 'Your gift to ACFI is received. May the Lord bless you richly.',
    tone: 'is-success',
  },
  cancelled: {
    title: 'Checkout cancelled',
    body: 'No worries — your card was not charged. You can give whenever you’re ready.',
    tone: 'is-cancelled',
  },
};

export function handleGiftResult(): void {
  const params = new URLSearchParams(window.location.search);
  const gift = params.get('gift');
  if (gift !== 'success' && gift !== 'cancelled') return;

  showBanner(gift);

  // Remove gift params so a refresh doesn't re-show the banner.
  params.delete('gift');
  params.delete('session_id');
  const clean = window.location.pathname + (params.toString() ? `?${params}` : '') + '#give';
  window.history.replaceState(null, '', clean);
}

function showBanner(outcome: GiftOutcome): void {
  const { title, body, tone } = MESSAGES[outcome];

  const banner = h(
    'div',
    { class: `gift-banner ${tone}`, attrs: { role: 'status' } },
    h('div', { class: 'gift-banner-text' }, h('strong', {}, title), h('span', {}, body)),
    h('button', { type: 'button', class: 'gift-banner-close', attrs: { 'aria-label': 'Dismiss' } }, '×'),
  );

  banner.querySelector('button')!.addEventListener('click', () => banner.remove());
  document.body.append(banner);
  requestAnimationFrame(() => banner.classList.add('is-shown'));
  window.setTimeout(() => banner.classList.add('is-shown'), 10);
}
