/**
 * Builds the giving card — the amount field, Fund picker, Frequency pills, and
 * the "Continue to give" button — and wires those controls to a DonationDraft
 * and the checkout client. It owns presentation and interaction only; money
 * rules and networking live elsewhere. One job: the give experience.
 */

import { h } from '../dom/h.js';
import { FUNDS, DEFAULT_FUND_ID } from '../../shared/funds.js';
import { FREQUENCIES, DEFAULT_FREQUENCY_ID } from '../../shared/frequencies.js';
import { parseDollarsToCents, centsToInputString } from '../../shared/money.js';
import { content } from '../content/site.js';
import { DonationDraft } from './donation-draft.js';
import type { CheckoutClient } from './checkout-client.js';

const PRESETS_CENTS = [2500, 5000, 10000, 25000];

export function createGiveWidget(client: CheckoutClient): HTMLElement {
  const draft = new DonationDraft();

  // --- Amount field ------------------------------------------------------
  const amountInput = h('input', {
    class: 'amount-input',
    attrs: {
      inputmode: 'decimal',
      autocomplete: 'off',
      'aria-label': 'Gift amount in US dollars',
      value: '0',
    },
  });

  const amountField = h(
    'div',
    { class: 'amount-field' },
    h('span', { class: 'amount-currency' }, '$'),
    amountInput,
  );

  const presetRow = h('div', { class: 'amount-presets' });
  const presetButtons = PRESETS_CENTS.map((cents) => {
    const btn = h(
      'button',
      { type: 'button', class: 'preset', attrs: { 'data-cents': String(cents) } },
      `$${cents / 100}`,
    );
    btn.addEventListener('click', () => {
      amountInput.value = centsToInputString(cents);
      syncAmount();
      amountInput.focus();
    });
    presetRow.append(btn);
    return btn;
  });

  // --- Fund picker -------------------------------------------------------
  const fundSelect = h('select', { id: 'give-fund', class: 'fund-select' });
  for (const fund of FUNDS) {
    const opt = h('option', { attrs: { value: fund.id } }, fund.label);
    if (fund.id === DEFAULT_FUND_ID) opt.selected = true;
    fundSelect.append(opt);
  }
  fundSelect.addEventListener('change', () => draft.setFund(fundSelect.value));

  // --- Frequency pills ---------------------------------------------------
  const freqGrid = h('div', {
    class: 'freq-grid',
    attrs: { role: 'radiogroup', 'aria-label': 'Giving frequency' },
  });
  const freqButtons = FREQUENCIES.map((freq) => {
    const selected = freq.id === DEFAULT_FREQUENCY_ID;
    const pill = h(
      'button',
      {
        type: 'button',
        class: 'freq-pill' + (selected ? ' is-active' : ''),
        attrs: { role: 'radio', 'aria-checked': String(selected), 'data-freq': freq.id },
      },
      freq.label,
    );
    pill.addEventListener('click', () => selectFrequency(freq.id));
    freqGrid.append(pill);
    return pill;
  });

  // --- Status + submit ---------------------------------------------------
  const error = h('p', { class: 'give-error', attrs: { role: 'alert', 'aria-live': 'polite' } });
  error.hidden = true;

  const submit = h('button', { type: 'button', class: 'btn-give' }, 'Continue to give');
  submit.addEventListener('click', () => void onSubmit());

  const assurance = h('p', { class: 'give-assurance' }, content.give.assurance);

  // --- Behaviour ---------------------------------------------------------
  function syncAmount(): void {
    const cents = parseDollarsToCents(amountInput.value) ?? 0;
    draft.setAmountCents(cents);
    for (const btn of presetButtons) {
      btn.classList.toggle('is-active', Number(btn.dataset.cents) === cents && cents > 0);
    }
    clearError();
  }

  function selectFrequency(id: string): void {
    draft.setFrequency(id);
    for (const btn of freqButtons) {
      const active = btn.dataset.freq === id;
      btn.classList.toggle('is-active', active);
      btn.setAttribute('aria-checked', String(active));
    }
  }

  function showError(message: string): void {
    error.textContent = message;
    error.hidden = false;
  }
  function clearError(): void {
    error.hidden = true;
  }

  async function onSubmit(): Promise<void> {
    syncAmount();
    const problem = draft.firstError();
    if (problem) {
      showError(problem);
      return;
    }
    setLoading(true);
    try {
      const url = await client.createSession(draft.toRequest());
      window.location.href = url;
    } catch (err) {
      showError(err instanceof Error ? err.message : 'Something went wrong. Please try again.');
      setLoading(false);
    }
  }

  function setLoading(loading: boolean): void {
    submit.disabled = loading;
    submit.classList.toggle('is-loading', loading);
    submit.textContent = loading ? 'Redirecting to secure checkout…' : 'Continue to give';
  }

  amountInput.addEventListener('input', syncAmount);
  amountInput.addEventListener('focus', () => {
    if (amountInput.value === '0') amountInput.value = '';
  });
  amountInput.addEventListener('blur', () => {
    if (amountInput.value.trim() === '') {
      amountInput.value = '0';
      syncAmount();
    }
  });

  // --- Assemble ----------------------------------------------------------
  return h(
    'div',
    { class: 'give-card', attrs: { 'data-reveal': '' } },
    amountField,
    presetRow,
    field('Fund', fundSelect, true),
    field('Frequency', freqGrid),
    error,
    submit,
    assurance,
  );
}

/** A labelled control group inside the give card. */
function field(label: string, control: HTMLElement, wrapSelect = false): HTMLElement {
  return h(
    'div',
    { class: 'give-group' },
    h('span', { class: 'give-label' }, label),
    wrapSelect ? h('div', { class: 'select-wrap' }, control) : control,
  );
}
