/**
 * Composition root for the page. Imports styles, builds each section, mounts
 * them in order, then turns on scroll-reveal and the post-checkout banner.
 * The only file that knows the page's overall shape. One job: assemble the site.
 */

import './styles/index.css';

import { createNavbar } from './sections/navbar.js';
import { createBanners } from './sections/banners.js';
import { createHero } from './sections/hero.js';
import { createWelcome } from './sections/welcome.js';
import { createStory } from './sections/story.js';
import { createPastor } from './sections/pastor.js';
import { createBeliefs } from './sections/beliefs.js';
import { createMinistries } from './sections/ministries.js';
import { createGallery } from './sections/gallery.js';
import { createEvents } from './sections/events.js';
import { createInvite } from './sections/invite.js';
import { createVisit } from './sections/visit.js';
import { createWatch } from './sections/watch.js';
import { createGive } from './sections/give.js';
import { createFooter } from './sections/footer.js';
import { initReveal } from './dom/reveal.js';
import { handleGiftResult } from './give/gift-result.js';

function mount(): void {
  const root = document.getElementById('app');
  if (!root) throw new Error('#app root element not found.');

  const main = document.createElement('main');
  const hero = createHero();
  main.append(
    hero,
    createWelcome(),
    createStory(),
    createPastor(),
    createBeliefs(),
    createMinistries(),
    createGallery(),
    createEvents(),
    createInvite(),
    createVisit(),
    createWatch(),
    createGive(),
  );

  root.append(createNavbar(), main, createFooter());

  // The corner ribbons are fixed in the top-left and fade out as the page scrolls.
  const banners = createBanners();
  if (banners) {
    document.body.append(banners);
    document.body.classList.add('has-banners');
    document.body.dataset.banners = String(banners.childElementCount);
  }

  initReveal();
  handleGiftResult();
}

mount();
