/**
 * "Weekly Services" — Sunday service time, the worship location with a map link,
 * and the latest sermon. One job: help people come this Sunday.
 */

import { h } from '../dom/h.js';
import { content } from '../content/site.js';

export function createVisit(): HTMLElement {
  const { visit } = content;
  const mapHref = `https://maps.google.com/?q=${encodeURIComponent(content.org.worship.mapsQuery)}`;

  const service = h(
    'div',
    { class: 'visit-card visit-service', attrs: { 'data-reveal': '' } },
    h('span', { class: 'visit-kicker' }, visit.service.heading),
    h('p', { class: 'visit-time' }, visit.service.time),
    h('p', { class: 'visit-note' }, visit.service.mode),
  );

  const location = h(
    'a',
    {
      class: 'visit-card visit-location',
      href: mapHref,
      attrs: { 'data-reveal': '', target: '_blank', rel: 'noopener' },
    },
    h('span', { class: 'visit-kicker' }, visit.location.heading),
    h('p', { class: 'visit-venue' }, visit.location.venue),
    h('p', { class: 'visit-address' }, visit.location.address),
    h('span', { class: 'visit-maplink' }, 'Open in Maps →'),
  );

  return h(
    'section',
    { class: 'section visit', id: 'visit' },
    h(
      'div',
      { class: 'container' },
      h('p', { class: 'eyebrow', attrs: { 'data-reveal': '' } }, visit.eyebrow),
      h('h2', { class: 'section-title', attrs: { 'data-reveal': '' } }, visit.title),
      h('div', { class: 'visit-grid visit-grid-2' }, service, location),
    ),
  );
}
