/**
 * "Our Vision and Mission", the three Core Tenets, and the full "7 Canons"
 * Statement of Faith — every canon shown in full (no click-to-expand), verbatim,
 * in a compact two-column layout. One job: what ACFI believes.
 */

import { h } from '../dom/h.js';
import { content } from '../content/site.js';

export function createBeliefs(): HTMLElement {
  const { beliefs, tenets } = content;

  const visionMission = h(
    'div',
    { class: 'vm-grid', attrs: { 'data-reveal': '' } },
    statement(beliefs.visionLabel, beliefs.vision),
    statement(beliefs.missionLabel, beliefs.mission),
  );

  const coreTenets = h(
    'div',
    { class: 'tenets-block', attrs: { 'data-reveal': '' } },
    h('h3', { class: 'tenets-block-heading' }, tenets.eyebrow),
    h(
      'div',
      { class: 'tenets-cards' },
      ...tenets.items.map((t) =>
        h(
          'div',
          { class: 'tenet-card' },
          h('h4', { class: 'tenet-card-name' }, t.name),
          h('p', { class: 'tenet-card-line' }, t.line),
        ),
      ),
    ),
  );

  const canons = h(
    'div',
    { class: 'canons', attrs: { 'data-reveal': '' } },
    h('h3', { class: 'canons-heading' }, beliefs.canonsHeading),
    h(
      'ol',
      { class: 'canon-list' },
      ...beliefs.canons.map((canon) =>
        h(
          'li',
          { class: 'canon' },
          h('p', { class: 'canon-text' }, canon.text),
          h('p', { class: 'canon-refs' }, canon.refs),
        ),
      ),
    ),
  );

  return h(
    'section',
    { class: 'section beliefs', id: 'beliefs' },
    h(
      'div',
      { class: 'container' },
      h('p', { class: 'eyebrow', attrs: { 'data-reveal': '' } }, beliefs.eyebrow),
      visionMission,
      coreTenets,
      canons,
    ),
  );
}

function statement(label: string, text: string): HTMLElement {
  return h(
    'div',
    { class: 'vm-card' },
    h('span', { class: 'vm-label' }, label),
    h('p', { class: 'vm-text' }, text),
  );
}
