/**
 * A single accessible dialog box built on the native <dialog> element — focus
 * trapping, Escape-to-close, and an inert backdrop come for free. The body is
 * expected to provide its own header/content; the close button floats over the
 * top-right. One job: show content in a large, professional modal.
 */

import { h } from './h.js';

export function openModal(title: string, body: HTMLElement): void {
  const closeBtn = h(
    'button',
    { type: 'button', class: 'modal-close', attrs: { 'aria-label': 'Close' } },
    '×',
  );

  const dialog = h(
    'dialog',
    { class: 'modal', attrs: { 'aria-label': title } },
    closeBtn,
    h('div', { class: 'modal-scroll' }, body),
  ) as HTMLDialogElement;

  const close = () => dialog.close();

  closeBtn.addEventListener('click', close);
  dialog.addEventListener('click', (ev) => {
    if (ev.target === dialog) close();
  });
  dialog.addEventListener('close', () => {
    dialog.remove();
    document.body.classList.remove('modal-open');
  });

  document.body.append(dialog);
  document.body.classList.add('modal-open');
  dialog.showModal();
  dialog.scrollTop = 0;
}
