/**
 * "Pastor's Note" — Pastor Vinod Abraham's photo with a short excerpt of his
 * welcome, and a "Read the full message" button opening a dialog with the
 * complete verbatim letter. One job: present the pastor's note, concisely.
 */

import { h } from '../dom/h.js';
import { openModal } from '../dom/modal.js';
import { content } from '../content/site.js';

export function createPastor(): HTMLElement {
  const { pastor } = content;

  const aside = h(
    'div',
    { class: 'pastor-card', attrs: { 'data-reveal': '' } },
    h('img', { class: 'pastor-photo', src: pastor.photo, alt: pastor.name }),
    h('p', { class: 'pastor-name' }, pastor.name),
    h('p', { class: 'pastor-role' }, pastor.role),
  );

  const readMore = h('button', { type: 'button', class: 'read-more' }, 'Read the full message →');
  readMore.addEventListener('click', () => openModal(pastor.title, buildFull()));

  const letter = h(
    'div',
    { class: 'pastor-letter' },
    h('p', { class: 'eyebrow', attrs: { 'data-reveal': '' } }, pastor.eyebrow),
    h('h2', { class: 'section-title pastor-title', attrs: { 'data-reveal': '' } }, pastor.title),
    h('p', { class: 'pastor-greeting', attrs: { 'data-reveal': '' } }, pastor.greeting),
    h('p', { class: 'pastor-greeting2', attrs: { 'data-reveal': '' } }, pastor.greeting2),
    h('p', { class: 'pastor-paragraph', attrs: { 'data-reveal': '' } }, pastor.paragraphs[0]),
    h('p', { class: 'pastor-paragraph', attrs: { 'data-reveal': '' } }, pastor.paragraphs[1]),
    readMore,
  );

  return h(
    'section',
    { class: 'section pastor', id: 'pastor' },
    h('div', { class: 'container pastor-grid' }, aside, letter),
  );
}

function buildFull(): HTMLElement {
  const { pastor } = content;
  const header = h(
    'header',
    { class: 'modal-header' },
    h('p', { class: 'modal-eyebrow' }, pastor.role),
    h('h2', { class: 'modal-title' }, pastor.name),
    h('p', { class: 'modal-verse' }, pastor.greeting + ' ' + pastor.greeting2),
  );
  const body = h(
    'div',
    { class: 'modal-content' },
    ...pastor.paragraphs.map((p) => h('p', { class: 'modal-paragraph' }, p)),
    h(
      'div',
      { class: 'modal-sign' },
      h('span', { class: 'pastor-signoff' }, pastor.signoff),
      h('span', { class: 'pastor-signature' }, pastor.name),
    ),
  );
  return h('div', { class: 'modal-body' }, header, body);
}
