/**
 * The hero: a full-width congregation photo under a blue brand overlay, with the
 * large ACFI emblem, the church name, the welcome headline, Sunday service time,
 * and two calls to action on top. One job: the hero.
 */

import { h } from '../dom/h.js';
import { content } from '../content/site.js';

export function createHero(): HTMLElement {
  const { hero, org } = content;

  const media = h('div', { class: 'hero-media', attrs: { 'aria-hidden': 'true' } });

  const inner = h(
    'div',
    { class: 'container hero-content' },
    h('img', {
      class: 'hero-emblem',
      src: 'img/acfi-mark-white.png',
      alt: 'Austin Christian Fellowship of India emblem',
      attrs: { 'data-reveal': '' },
    }),
    h('p', { class: 'hero-badge', attrs: { 'data-reveal': '' } }, hero.badge),
    h('h1', { class: 'hero-title', attrs: { 'data-reveal': '' } }, hero.title),
    h('p', { class: 'hero-org', attrs: { 'data-reveal': '' } }, org.name),
    h('p', { class: 'hero-lede', attrs: { 'data-reveal': '' } }, hero.lede),
    h(
      'div',
      { class: 'hero-service', attrs: { 'data-reveal': '' } },
      h('span', { class: 'hero-service-dot' }),
      h(
        'span',
        {},
        h('strong', {}, hero.service),
        h('span', { class: 'hero-service-note' }, hero.serviceNote),
      ),
    ),
    h(
      'div',
      { class: 'hero-cta', attrs: { 'data-reveal': '' } },
      h('a', { class: 'btn btn-primary', href: hero.primaryCta.href }, hero.primaryCta.label),
      h('a', { class: 'btn btn-on-photo', href: hero.secondaryCta.href }, hero.secondaryCta.label),
    ),
  );

  return h('section', { class: 'hero', id: 'home' }, media, inner);
}
