/**
 * "Events" — ACFI's weekly and monthly rhythm, plus featured events (CFC,
 * IGNITE) with their flyers. All times and details verbatim. One job: events.
 */

import { h } from '../dom/h.js';
import { content } from '../content/site.js';

interface Recurring {
  name: string;
  when: string;
}

export function createEvents(): HTMLElement {
  const { events } = content;

  const schedule = h(
    'div',
    { class: 'events-schedule' },
    column(events.weeklyHeading, events.weekly),
    column(events.monthlyHeading, events.monthly),
  );

  const featured = h(
    'div',
    { class: 'events-featured', attrs: { 'data-reveal': '' } },
    ...events.featured.map((ev) =>
      h(
        'figure',
        { class: 'event-card' },
        h('div', { class: 'event-image' }, h('img', { src: ev.image, alt: ev.name })),
        h('figcaption', { class: 'event-cap' }, h('span', { class: 'event-name' }, ev.name)),
      ),
    ),
  );

  return h(
    'section',
    { class: 'section events', id: 'events' },
    h(
      'div',
      { class: 'container' },
      h('p', { class: 'eyebrow', attrs: { 'data-reveal': '' } }, events.eyebrow),
      h('h2', { class: 'section-title', attrs: { 'data-reveal': '' } }, events.title),
      schedule,
      h('h3', { class: 'events-featured-heading', attrs: { 'data-reveal': '' } }, events.featuredHeading),
      featured,
    ),
  );
}

function column(heading: string, items: readonly Recurring[]): HTMLElement {
  return h(
    'div',
    { class: 'events-col', attrs: { 'data-reveal': '' } },
    h('h3', { class: 'events-col-heading' }, heading),
    ...items.map((it) =>
      h(
        'div',
        { class: 'event-item' },
        h('p', { class: 'event-item-name' }, it.name),
        h('p', { class: 'event-item-when' }, it.when),
      ),
    ),
  );
}
