/**
 * A full-width invitation band — a worship photo under a blue overlay with the
 * church's own welcome line. One job: a warm, image-led call to come.
 */

import { h } from '../dom/h.js';
import { content } from '../content/site.js';

export function createInvite(): HTMLElement {
  const { invite } = content;

  return h(
    'section',
    { class: 'invite', attrs: { 'aria-label': 'You are welcome' } },
    h('img', { class: 'invite-img', src: invite.image, alt: '' }),
    h('div', { class: 'invite-overlay' }),
    h(
      'div',
      { class: 'container invite-content' },
      h('p', { class: 'invite-text', attrs: { 'data-reveal': '' } }, invite.text),
      h('p', { class: 'invite-sub', attrs: { 'data-reveal': '' } }, invite.sub),
    ),
  );
}
