/**
 * The donation request contract — the exact shape that crosses the wire from
 * browser to server — and the one validator both sides trust. The client builds
 * and pre-checks it; the server re-checks the identical rules before ever
 * touching Stripe. One job: define and validate a gift request.
 */

import { isValidAmount, MIN_AMOUNT_CENTS, MAX_AMOUNT_CENTS, formatCents } from './money.js';
import { getFrequency } from './frequencies.js';
import { getFund } from './funds.js';

export interface DonationRequest {
  amountCents: number;
  fundId: string;
  frequencyId: string;
}

export interface ValidationResult {
  ok: boolean;
  errors: string[];
}

/**
 * Validate an untrusted donation request. Never throws — returns a list of
 * human-readable problems so the caller (UI or API) can decide how to present them.
 */
export function validateDonationRequest(req: unknown): ValidationResult {
  const errors: string[] = [];

  if (typeof req !== 'object' || req === null) {
    return { ok: false, errors: ['Request body must be an object.'] };
  }

  const { amountCents, fundId, frequencyId } = req as Record<string, unknown>;

  if (typeof amountCents !== 'number' || !isValidAmount(amountCents)) {
    errors.push(
      `Amount must be between ${formatCents(MIN_AMOUNT_CENTS)} and ${formatCents(MAX_AMOUNT_CENTS)}.`,
    );
  }
  if (typeof fundId !== 'string' || !getFund(fundId)) {
    errors.push('Please choose a valid fund.');
  }
  if (typeof frequencyId !== 'string' || !getFrequency(frequencyId)) {
    errors.push('Please choose a valid frequency.');
  }

  return { ok: errors.length === 0, errors };
}
