/**
 * The in-progress gift the giver is composing: an amount, a fund, and a
 * frequency. Holds state and knows how to validate itself and turn into the
 * wire request — but knows nothing about the DOM or the network. One job: model
 * a gift-in-progress.
 */

import { DEFAULT_FUND_ID } from '../../shared/funds.js';
import { DEFAULT_FREQUENCY_ID } from '../../shared/frequencies.js';
import { validateDonationRequest, type DonationRequest } from '../../shared/donation.js';

export class DonationDraft {
  private amountCents = 0;
  private fundId: string = DEFAULT_FUND_ID;
  private frequencyId: string = DEFAULT_FREQUENCY_ID;

  setAmountCents(cents: number): void {
    this.amountCents = Number.isFinite(cents) && cents > 0 ? Math.round(cents) : 0;
  }
  setFund(id: string): void {
    this.fundId = id;
  }
  setFrequency(id: string): void {
    this.frequencyId = id;
  }

  getAmountCents(): number {
    return this.amountCents;
  }
  getFundId(): string {
    return this.fundId;
  }
  getFrequencyId(): string {
    return this.frequencyId;
  }

  toRequest(): DonationRequest {
    return {
      amountCents: this.amountCents,
      fundId: this.fundId,
      frequencyId: this.frequencyId,
    };
  }

  /** First validation error, or null when the draft is ready to submit. */
  firstError(): string | null {
    const result = validateDonationRequest(this.toRequest());
    return result.ok ? null : result.errors[0]!;
  }
}
