/**
 * A self-contained image slideshow: fading slides, prev/next arrows, clickable
 * dots, and gentle autoplay that pauses on hover and respects reduced-motion.
 * One job: cycle through a set of images.
 */

import { h } from './h.js';

export interface Slide {
  src: string;
  alt: string;
}

export function createSlideshow(slides: Slide[]): HTMLElement {
  let index = 0;

  const slideEls = slides.map((s, i) =>
    h('img', {
      class: 'slide' + (i === 0 ? ' is-active' : ''),
      src: s.src,
      alt: s.alt,
      attrs: i === 0 ? {} : { loading: 'lazy' },
    }),
  );

  const dots = slides.map((_, i) =>
    h('button', {
      type: 'button',
      class: 'slide-dot' + (i === 0 ? ' is-active' : ''),
      attrs: { 'aria-label': `Go to slide ${i + 1}` },
    }),
  );

  const show = (next: number) => {
    index = (next + slides.length) % slides.length;
    slideEls.forEach((el, i) => el.classList.toggle('is-active', i === index));
    dots.forEach((d, i) => d.classList.toggle('is-active', i === index));
  };

  dots.forEach((d, i) => d.addEventListener('click', () => { show(i); restart(); }));

  const prev = h('button', { type: 'button', class: 'slide-arrow slide-prev', attrs: { 'aria-label': 'Previous' } }, '‹');
  const next = h('button', { type: 'button', class: 'slide-arrow slide-next', attrs: { 'aria-label': 'Next' } }, '›');
  prev.addEventListener('click', () => { show(index - 1); restart(); });
  next.addEventListener('click', () => { show(index + 1); restart(); });

  const reduce = window.matchMedia('(prefers-reduced-motion: reduce)').matches;
  let timer = 0;
  const start = () => {
    if (reduce || slides.length < 2) return;
    timer = window.setInterval(() => show(index + 1), 5000);
  };
  const stop = () => window.clearInterval(timer);
  const restart = () => { stop(); start(); };

  const root = h(
    'div',
    { class: 'slideshow' },
    h('div', { class: 'slide-track' }, ...slideEls),
    prev,
    next,
    h('div', { class: 'slide-dots' }, ...dots),
  );

  root.addEventListener('mouseenter', stop);
  root.addEventListener('mouseleave', start);
  start();

  return root;
}
