/**
 * Typed bridge to the runtime configuration set by scripts/config/*.js (on
 * window.ACFI). Each config file owns one concern; this module just reads them
 * with safe fallbacks so the UI never breaks if a file is edited or missing.
 * One job: expose configuration to the app as typed values.
 */

export interface YouTubeConfig {
  channelUrl: string;
  latestSermon: { title: string; videoId: string };
  videoIds: string[];
}

export interface SocialConfig {
  youtube: string;
  facebook: string;
  email: string;
}

export interface PaymentsConfig {
  stripePublishableKey: string;
  checkoutEndpoint: string;
}

export interface Banner {
  text: string;
  href?: string;
  /** Ribbon colour: 'orange' | 'blue' | 'red'. Defaults by position when omitted. */
  color?: string;
}

interface AcfiGlobal {
  youtube?: Partial<YouTubeConfig>;
  social?: Partial<SocialConfig>;
  payments?: Partial<PaymentsConfig>;
  banners?: Banner[];
}

declare global {
  interface Window {
    ACFI?: AcfiGlobal;
  }
}

const g: AcfiGlobal = window.ACFI ?? {};

export const youtube: YouTubeConfig = {
  channelUrl: 'https://www.youtube.com/user/ACFIChannel',
  latestSermon: { title: '', videoId: '' },
  videoIds: [],
  ...g.youtube,
};

export const social: SocialConfig = {
  youtube: 'https://www.youtube.com/user/ACFIChannel',
  facebook: 'https://www.facebook.com/share/oLEF5G13MveTsycP/',
  email: 'info@acfi.cc',
  ...g.social,
};

export const payments: PaymentsConfig = {
  stripePublishableKey: '',
  checkoutEndpoint: '/api/create-checkout-session',
  ...g.payments,
};

/** At most three corner banners are ever shown. */
export const banners: Banner[] = (g.banners ?? []).filter((b) => b && b.text).slice(0, 3);
