/**
 * "A Brief History of our Church" — a short intro with a congregation photo, and
 * a "Read the full history" button that opens a dialog with the complete
 * verbatim history, the "Presently involved in" list, and the closing verse.
 * One job: tell the church's history, concisely up front.
 */

import { h } from '../dom/h.js';
import { openModal } from '../dom/modal.js';
import { content } from '../content/site.js';

export function createStory(): HTMLElement {
  const { story } = content;

  const readMore = h('button', { type: 'button', class: 'read-more read-more-dark' }, 'Read the full history →');
  readMore.addEventListener('click', () => openModal(story.title, buildFull()));

  const prose = h(
    'div',
    { class: 'story-prose' },
    h('p', { class: 'eyebrow eyebrow-light', attrs: { 'data-reveal': '' } }, 'Our Story'),
    h('h2', { class: 'section-title story-title', attrs: { 'data-reveal': '' } }, story.title),
    h('p', { class: 'story-paragraph', attrs: { 'data-reveal': '' } }, story.paragraphs[0]),
    h('p', { class: 'story-paragraph', attrs: { 'data-reveal': '' } }, story.paragraphs[1]),
    readMore,
  );

  const media = h(
    'figure',
    { class: 'story-media', attrs: { 'data-reveal': '' } },
    h('img', { class: 'story-img', src: story.image, alt: story.imageCaption }),
    h('figcaption', { class: 'story-caption' }, story.imageCaption),
  );

  return h(
    'section',
    { class: 'section story', id: 'story' },
    h('div', { class: 'container story-grid' }, prose, media),
  );
}

function buildFull(): HTMLElement {
  const { story } = content;
  const header = h(
    'header',
    { class: 'modal-header' },
    h('p', { class: 'modal-eyebrow' }, 'Our Story'),
    h('h2', { class: 'modal-title' }, story.title),
  );
  const body = h(
    'div',
    { class: 'modal-content' },
    ...story.paragraphs.map((p) => h('p', { class: 'modal-paragraph' }, p)),
    h(
      'div',
      { class: 'modal-section' },
      h('h3', { class: 'modal-section-heading' }, story.involvedHeading),
      h('ul', { class: 'modal-list' }, ...story.involved.map((it) => h('li', {}, it))),
    ),
    h('p', { class: 'modal-paragraph' }, story.closing),
    h('p', { class: 'modal-verse modal-verse-dark' }, story.closingVerse),
  );
  return h('div', { class: 'modal-body' }, header, body);
}
