/**
 * The smallest element builder that keeps section code declarative and free of
 * repetitive document.createElement noise. One job: build a DOM node from a tag,
 * props, and children. No framework, no virtual DOM — just real elements.
 */

type Child = Node | string | number | false | null | undefined;

export interface Props {
  class?: string;
  id?: string;
  html?: string;
  href?: string;
  src?: string;
  alt?: string;
  type?: string;
  /** Arbitrary attributes (aria-*, role, data-*, inputmode, etc.). */
  attrs?: Record<string, string>;
  /** Event handlers keyed by event name, e.g. { click: fn }. */
  on?: Partial<Record<keyof HTMLElementEventMap, (ev: Event) => void>>;
}

export function h<K extends keyof HTMLElementTagNameMap>(
  tag: K,
  props: Props = {},
  ...children: Child[]
): HTMLElementTagNameMap[K] {
  const el = document.createElement(tag);

  if (props.class) el.className = props.class;
  if (props.id) el.id = props.id;
  if (props.href && 'href' in el) (el as HTMLAnchorElement).href = props.href;
  if (props.src && 'src' in el) (el as HTMLImageElement).src = props.src;
  if (props.alt && 'alt' in el) (el as HTMLImageElement).alt = props.alt;
  if (props.type) el.setAttribute('type', props.type);
  if (props.html !== undefined) el.innerHTML = props.html;

  if (props.attrs) {
    for (const [key, value] of Object.entries(props.attrs)) el.setAttribute(key, value);
  }
  if (props.on) {
    for (const [event, handler] of Object.entries(props.on)) {
      el.addEventListener(event, handler as EventListener);
    }
  }

  for (const child of children) {
    if (child === false || child === null || child === undefined) continue;
    el.append(child instanceof Node ? child : document.createTextNode(String(child)));
  }

  return el;
}
