/**
 * The giving section: the persuasive copy and the Building Fund + other methods
 * on one side, and the interactive give card on the other. The card itself is
 * built by give-widget; this section places it. One job: frame the ask.
 */

import { h } from '../dom/h.js';
import { content } from '../content/site.js';
import { createGiveWidget } from '../give/give-widget.js';
import { HttpCheckoutClient } from '../give/checkout-client.js';

export function createGive(): HTMLElement {
  const { give } = content;

  const widget = createGiveWidget(new HttpCheckoutClient());

  const aside = h(
    'div',
    { class: 'give-aside' },
    h('p', { class: 'eyebrow eyebrow-light', attrs: { 'data-reveal': '' } }, give.eyebrow),
    h('h2', { class: 'section-title give-title', attrs: { 'data-reveal': '' } }, give.title),
    h('p', { class: 'section-lede give-lede', attrs: { 'data-reveal': '' } }, give.lede),
    h(
      'div',
      { class: 'building-fund', attrs: { 'data-reveal': '' } },
      h('h3', { class: 'building-title' }, give.buildingFund.title),
      h('p', { class: 'building-blurb' }, give.buildingFund.blurb),
    ),
    h(
      'ul',
      { class: 'give-methods', attrs: { 'data-reveal': '' } },
      ...give.otherMethods.map((m) =>
        h(
          'li',
          { class: 'give-method' },
          h('strong', {}, m.name),
          h('span', {}, m.detail),
        ),
      ),
    ),
  );

  return h(
    'section',
    { class: 'section give', id: 'give' },
    h('div', { class: 'container give-grid' }, aside, widget),
  );
}
