/**
 * The browser's one link to the giving API. Sends a validated donation request
 * and returns the Stripe Checkout URL to redirect to. One job: speak HTTP to the
 * server and surface a clean message on failure.
 */

import type { DonationRequest } from '../../shared/donation.js';
import { payments } from '../config.js';

export interface CheckoutClient {
  createSession(request: DonationRequest): Promise<string>;
}

export class HttpCheckoutClient implements CheckoutClient {
  constructor(private readonly endpoint = payments.checkoutEndpoint) {}

  async createSession(request: DonationRequest): Promise<string> {
    let response: Response;
    try {
      response = await fetch(this.endpoint, {
        method: 'POST',
        headers: { 'content-type': 'application/json' },
        body: JSON.stringify(request),
      });
    } catch {
      throw new Error('We couldn’t reach the server. Please check your connection and try again.');
    }

    const data = (await response.json().catch(() => ({}))) as { url?: string; error?: string };

    if (!response.ok || !data.url) {
      throw new Error(data.error ?? 'Something went wrong starting checkout. Please try again.');
    }
    return data.url;
  }
}
