/**
 * The closing footer: brand identity, a single concise contact line, social
 * icon links, and a legal bar — deliberately minimal so it doesn't echo content
 * already on the page. Social links come from runtime config. One job: sign off.
 */

import { h } from '../dom/h.js';
import { content } from '../content/site.js';
import { social } from '../config.js';

const ICONS: Record<string, string> = {
  youtube:
    '<svg viewBox="0 0 24 24" width="20" height="20" fill="currentColor" aria-hidden="true"><path d="M23.5 6.2a3 3 0 0 0-2.1-2.1C19.5 3.5 12 3.5 12 3.5s-7.5 0-9.4.6A3 3 0 0 0 .5 6.2 31 31 0 0 0 0 12a31 31 0 0 0 .5 5.8 3 3 0 0 0 2.1 2.1c1.9.6 9.4.6 9.4.6s7.5 0 9.4-.6a3 3 0 0 0 2.1-2.1A31 31 0 0 0 24 12a31 31 0 0 0-.5-5.8ZM9.6 15.6V8.4l6.3 3.6-6.3 3.6Z"/></svg>',
  facebook:
    '<svg viewBox="0 0 24 24" width="20" height="20" fill="currentColor" aria-hidden="true"><path d="M24 12a12 12 0 1 0-13.9 11.9v-8.4H7.1V12h3V9.4c0-3 1.8-4.6 4.5-4.6 1.3 0 2.6.2 2.6.2v2.9h-1.5c-1.4 0-1.9.9-1.9 1.8V12h3.3l-.5 3.5h-2.8v8.4A12 12 0 0 0 24 12Z"/></svg>',
  email:
    '<svg viewBox="0 0 24 24" width="20" height="20" fill="currentColor" aria-hidden="true"><path d="M2 4h20a2 2 0 0 1 2 2v12a2 2 0 0 1-2 2H2a2 2 0 0 1-2-2V6a2 2 0 0 1 2-2Zm10 7L2.2 5.8 2 6v.3l10 5.3 10-5.3V6l-.2-.2L12 11Z"/></svg>',
};

function iconLink(kind: keyof typeof ICONS, href: string, label: string): HTMLElement {
  return h('a', {
    class: 'footer-icon',
    href,
    html: ICONS[kind],
    attrs: { 'aria-label': label, target: '_blank', rel: 'noopener' },
  });
}

export function createFooter(): HTMLElement {
  const { footer, org } = content;

  const identity = h(
    'div',
    { class: 'footer-identity' },
    h('img', { class: 'footer-mark', src: 'img/acfi-mark-white.png', alt: '' }),
    h(
      'div',
      {},
      h('p', { class: 'footer-name' }, org.name),
      h('p', { class: 'footer-tagline' }, footer.tagline),
    ),
  );

  const contact = h(
    'div',
    { class: 'footer-contact' },
    h('p', { class: 'footer-addr' }, `${org.worship.venue} · ${org.worship.address}`),
    h(
      'p',
      { class: 'footer-reach' },
      h('a', { class: 'footer-reach-link', href: org.phoneHref }, org.phone),
      h('span', { class: 'footer-dot' }, '·'),
      h('a', { class: 'footer-reach-link', href: `mailto:${org.email}` }, org.email),
    ),
    h(
      'div',
      { class: 'footer-icons' },
      iconLink('youtube', social.youtube, 'YouTube'),
      iconLink('facebook', social.facebook, 'Facebook'),
      iconLink('email', `mailto:${social.email}`, 'Email'),
    ),
  );

  return h(
    'footer',
    { class: 'site-footer' },
    h('div', { class: 'container footer-main' }, identity, contact),
    h(
      'div',
      { class: 'container footer-base' },
      h('span', {}, `© 2026 ${org.name}`),
      h('span', {}, 'Soli Deo Gloria'),
    ),
  );
}
