/**
 * The funds a gift can be designated to. Drawn from ACFI's real ministries and
 * its active Church Building Fund campaign. One job: describe where money can go.
 * Add a new ministry fund here and it appears in the form and is accepted by the
 * server automatically — nothing else to touch.
 */

export type FundId = 'general' | 'missions' | 'building' | 'benevolence';

export interface Fund {
  id: FundId;
  label: string;
  description: string;
}

/** The exact funds ACFI lists on its giving page. */
export const FUNDS: readonly Fund[] = [
  { id: 'general', label: 'General Fund', description: 'General Fund' },
  { id: 'missions', label: 'Missions Fund', description: 'Missions Fund' },
  { id: 'building', label: 'Church Building Fund', description: 'Church Building Fund' },
  { id: 'benevolence', label: 'Benevolence Fund', description: 'Benevolence Fund' },
] as const;

export const DEFAULT_FUND_ID: FundId = 'general';

export function getFund(id: string): Fund | undefined {
  return FUNDS.find((f) => f.id === id);
}
