/**
 * "Watch" — embeds ACFI's latest sermon and links to its YouTube channel. The
 * video IDs and channel come from runtime config (scripts/config/youtube.js),
 * so they change without a rebuild. One job: bring ACFI's videos onto the page.
 */

import { h } from '../dom/h.js';
import { youtube } from '../config.js';

function embed(videoId: string, title: string): HTMLElement {
  return h(
    'div',
    { class: 'video-frame' },
    h('iframe', {
      src: `https://www.youtube-nocookie.com/embed/${videoId}?rel=0`,
      attrs: {
        title,
        loading: 'lazy',
        allow: 'accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture',
        allowfullscreen: 'true',
        referrerpolicy: 'strict-origin-when-cross-origin',
      },
    }),
  );
}

export function createWatch(): HTMLElement {
  const main = youtube.latestSermon.videoId
    ? h(
        'div',
        { class: 'watch-main', attrs: { 'data-reveal': '' } },
        embed(youtube.latestSermon.videoId, youtube.latestSermon.title),
        h('p', { class: 'watch-caption' }, youtube.latestSermon.title),
      )
    : null;

  const more = youtube.videoIds
    .filter((id) => id !== youtube.latestSermon.videoId)
    .map((id) => h('div', { class: 'watch-more-item', attrs: { 'data-reveal': '' } }, embed(id, 'ACFI video')));

  return h(
    'section',
    { class: 'section watch', id: 'watch' },
    h(
      'div',
      { class: 'container' },
      h('p', { class: 'eyebrow', attrs: { 'data-reveal': '' } }, 'Watch'),
      h('h2', { class: 'section-title', attrs: { 'data-reveal': '' } }, 'Messages from ACFI'),
      main,
      more.length ? h('div', { class: 'watch-more' }, ...more) : null,
      h(
        'a',
        {
          class: 'btn btn-primary watch-channel',
          href: youtube.channelUrl,
          attrs: { target: '_blank', rel: 'noopener', 'data-reveal': '' },
        },
        'Visit our YouTube channel →',
      ),
    ),
  );
}
