/**
 * The sticky header: the ACFI emblem, a breadcrumb that names the section you're
 * currently viewing (updated as you scroll), the in-page links, and a Give
 * button — with an accessible toggle for small screens. One job: navigation.
 */

import { h } from '../dom/h.js';
import { content } from '../content/site.js';

/** Section id -> human label for the breadcrumb (hero is "Home"). */
const SECTION_LABELS: Record<string, string> = {
  home: 'Home',
  ...Object.fromEntries(content.nav.map((n) => [n.href.replace('#', ''), n.label])),
};

export function createNavbar(): HTMLElement {
  const crumbCurrent = h('span', { class: 'crumb-current' }, 'Home');

  const breadcrumb = h(
    'a',
    { class: 'crumb', href: '#home', attrs: { 'aria-label': 'Current section' } },
    h('img', { class: 'crumb-emblem', src: 'img/acfi-mark-white.png', alt: '' }),
    h('span', { class: 'crumb-root' }, 'ACFI'),
    h('span', { class: 'crumb-sep' }, '›'),
    crumbCurrent,
  );

  const links = h(
    'nav',
    { class: 'nav-links', attrs: { 'aria-label': 'Primary' } },
    ...content.nav
      .filter((item) => item.href !== '#give')
      .map((item) => h('a', { class: 'nav-link', href: item.href }, item.label)),
    h('a', { class: 'nav-give', href: '#give' }, 'Give'),
  );

  const toggle = h(
    'button',
    {
      type: 'button',
      class: 'nav-toggle',
      attrs: { 'aria-label': 'Toggle menu', 'aria-expanded': 'false' },
    },
    h('span', { class: 'nav-toggle-bar' }),
    h('span', { class: 'nav-toggle-bar' }),
  );

  toggle.addEventListener('click', () => {
    const open = links.classList.toggle('is-open');
    toggle.classList.toggle('is-open', open);
    toggle.setAttribute('aria-expanded', String(open));
  });
  links.addEventListener('click', (ev) => {
    if ((ev.target as HTMLElement).tagName === 'A') {
      links.classList.remove('is-open');
      toggle.classList.remove('is-open');
      toggle.setAttribute('aria-expanded', 'false');
    }
  });

  const header = h(
    'header',
    { class: 'site-header', id: 'top' },
    h('div', { class: 'nav-inner' }, breadcrumb, links, toggle),
  );

  // Update the breadcrumb to the section currently in view.
  queueMicrotask(() => trackSections(crumbCurrent));

  return header;
}

function trackSections(target: HTMLElement): void {
  const sections = Array.from(document.querySelectorAll<HTMLElement>('section[id]'));
  if (sections.length === 0) return;

  let activeId = '';
  const setLabel = (id: string) => {
    if (id === activeId) return;
    activeId = id;
    target.textContent = SECTION_LABELS[id] ?? '';
  };

  // The active section is the last one whose top has scrolled up past the
  // activation line just below the sticky header — i.e. the section currently
  // filling the top of the reading area.
  let scheduled = 0;
  const update = () => {
    scheduled = 0;
    const header = document.querySelector<HTMLElement>('.site-header');
    const line = (header?.offsetHeight ?? 72) + 28;
    let active = sections[0]!;
    for (const section of sections) {
      if (section.getBoundingClientRect().top - line <= 0) active = section;
    }
    setLabel(active.id);
  };
  const onScroll = () => {
    if (!scheduled) scheduled = requestAnimationFrame(update);
  };

  window.addEventListener('scroll', onScroll, { passive: true });
  window.addEventListener('resize', onScroll, { passive: true });
  update();
}
