/**
 * The giving frequencies offered in the UI (mirrors the church's donation
 * mockup) plus how each one maps onto a Stripe billing cadence. Keeping the
 * cadence here — not in the server — means the UI labels and the billing
 * behaviour are defined together and stay in sync. One job: describe frequencies.
 */

export type FrequencyId =
  | 'once'
  | 'monthly'
  | 'weekly'
  | 'every_other_week'
  | 'twice_monthly';

/** How a frequency bills in Stripe. `recurring: false` => a one-time payment. */
export interface StripeCadence {
  recurring: boolean;
  interval?: 'week' | 'month';
  intervalCount?: number;
}

export interface Frequency {
  id: FrequencyId;
  label: string;
  cadence: StripeCadence;
  /** Optional honesty note surfaced to developers/operators. */
  note?: string;
}

export const FREQUENCIES: readonly Frequency[] = [
  { id: 'once', label: 'Once', cadence: { recurring: false } },
  { id: 'monthly', label: 'Monthly', cadence: { recurring: true, interval: 'month', intervalCount: 1 } },
  { id: 'weekly', label: 'Weekly', cadence: { recurring: true, interval: 'week', intervalCount: 1 } },
  {
    id: 'every_other_week',
    label: 'Every other week',
    cadence: { recurring: true, interval: 'week', intervalCount: 2 },
  },
  {
    id: 'twice_monthly',
    label: 'Twice monthly',
    cadence: { recurring: true, interval: 'week', intervalCount: 2 },
    note: 'Billed every two weeks (~twice a month). Stripe has no native semi-monthly cadence; revisit with Subscription Schedules if exact 1st/15th billing is required.',
  },
] as const;

export const DEFAULT_FREQUENCY_ID: FrequencyId = 'once';

export function getFrequency(id: string): Frequency | undefined {
  return FREQUENCIES.find((f) => f.id === id);
}
