/**
 * "Who we are?" — the church's own definition of itself, the diversity of the
 * family, and the A.C.F.I. acronym, all verbatim. One job: introduce the family.
 */

import { h } from '../dom/h.js';
import { content } from '../content/site.js';

export function createWelcome(): HTMLElement {
  const { welcome } = content;

  const intro = h(
    'div',
    { class: 'welcome-intro' },
    h('p', { class: 'eyebrow', attrs: { 'data-reveal': '' } }, welcome.eyebrow),
    h('p', { class: 'welcome-definition', attrs: { 'data-reveal': '' } }, welcome.definition),
    h('p', { class: 'welcome-diversity', attrs: { 'data-reveal': '' } }, welcome.diversity),
  );

  const tenets = h(
    'ul',
    { class: 'tenets', attrs: { 'data-reveal': '' } },
    ...welcome.acronym.map((t) =>
      h(
        'li',
        { class: 'tenet' },
        h('span', { class: 'tenet-letter' }, t.letter),
        h('span', { class: 'tenet-line' }, t.line),
      ),
    ),
  );

  return h(
    'section',
    { class: 'section welcome', id: 'welcome' },
    h('div', { class: 'container welcome-grid' }, intro, tenets),
  );
}
